# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    private int _currentHealth;
    
    public float money = 50f;
    public ShopItem[] shopItems;

    void Start()
    {
        _currentHealth = maxHealth;
    }

    // Damage calculation method
    public void TakeDamage(int damage)
    {
        _currentHealth -= damage;
        
        if (_currentHealth <= 0)
            Debug.Log("Player has died.");
    }
    
    // Currency addition method
    public bool AddMoney(float amount)
    {
        if (amount < 0 || money + amount < 0) 
            return false;
        
        money += amount;
        return true;
    }

    // Purchase item from shop
    public bool BuyItem(int index, float price)
    {
        if (index >= 0 && index < shopItems.Length && money >= price)
        {
            AddMoney(-price);
            Instantiate(shopItems[index].itemPrefab, transform.position + Vector3.up * 2, Quaternion.identity);
            return true;
        }
        
        Debug.Log("Purchase failed.");
        return false;
    }
}

// Shop item scriptable object
[Serializable]
public class ShopItem {
    public string name;
    public float price;
    public GameObject itemPrefab;
}